  function initGlobeCanvas() {
    if(window._animRafs&&window._animRafs['globe']) {
      cancelAnimationFrame(window._animRafs['globe']);
      delete window._animRafs['globe'];

    }
    const canvas=document.getElementById('globeCanvas');
    if(!canvas)return;
    const ctx=canvas.getContext('2d');
    const W=44,H=44,cx=22,cy=22,R=14;
    let angle=0;
    const latitudes=[-60,-30,0,30,60];
    const longitudes=[0,40,80,120,160,200,240,280,320];
    const _proj= {
      x:0,y:0,z:0
    };
    function project(lon,lat,rotY) {
      const latR=lat*Math.PI/180;
      const lonR=(lon+rotY)*Math.PI/180;
      const x3=Math.cos(latR)*Math.sin(lonR);
      const y3=Math.sin(latR);
      const z3=Math.cos(latR)*Math.cos(lonR);
      _proj.x=cx+R*x3;
      _proj.y=cy-R*y3;
      _proj.z=z3;
      return _proj;

    }
    const _glowGrd=ctx.createRadialGradient(cx,cy,R*0.6,cx,cy,R*1.3);
    _glowGrd.addColorStop(0,'rgba(180,100,255,0.0)');
    _glowGrd.addColorStop(1,'rgba(180,100,255,0.13)');
    let _gLastFrame=0;
    const _gFrameMs=1000/30;
    function draw(now) {
      if(now-_gLastFrame<_gFrameMs)return;
      _gLastFrame=now;
      ctx.clearRect(0,0,W,H);
      ctx.beginPath();
      ctx.arc(cx,cy,R*1.3,0,Math.PI*2);
      ctx.fillStyle=_glowGrd;
      ctx.fill();
      const deg=angle*(180/Math.PI);
      ctx.save();
      ctx.globalAlpha=0.18;
      ctx.strokeStyle='rgba(200,130,255,1)';
      ctx.lineWidth=0.6;
      ctx.beginPath();
      for(const lat of latitudes) {
        for(let lon=0;lon<360;lon+=4) {
          const p1=project(lon,lat,deg);
          const p2=project(lon+4,lat,deg);
          if(p1.z<0&&p2.z<0) {
            ctx.moveTo(p1.x,p1.y);
            ctx.lineTo(p2.x,p2.y);

          }

        }

      }
      ctx.stroke();
      ctx.beginPath();
      for(const lon of longitudes) {
        for(let lat=-88;lat<88;lat+=4) {
          const p1=project(lon,lat,deg);
          const p2=project(lon,lat+4,deg);
          if(p1.z<0&&p2.z<0) {
            ctx.moveTo(p1.x,p1.y);
            ctx.lineTo(p2.x,p2.y);

          }

        }

      }
      ctx.stroke();
      ctx.restore();
      ctx.save();
      ctx.beginPath();
      ctx.arc(cx,cy,R,0,Math.PI*2);
      ctx.clip();
      ctx.strokeStyle='rgba(200,130,255,0.45)';
      ctx.lineWidth=0.8;
      ctx.beginPath();
      for(const lat of latitudes) {
        if(lat===0)continue;
        let inSeg=false;
        for(let lon=0;lon<=360;lon+=3) {
          const p=project(lon,lat,deg);
          if(p.z>=0) {
            if(!inSeg) {
              ctx.moveTo(p.x,p.y);
              inSeg=true;

            }
            else ctx.lineTo(p.x,p.y);

          }
          else {
            inSeg=false;

          }

        }

      }
      ctx.stroke();
      ctx.strokeStyle='rgba(200,130,255,0.7)';
      ctx.lineWidth=1.1;
      ctx.beginPath();
       {
        let inSeg=false;
        for(let lon=0;lon<=360;lon+=3) {
          const p=project(lon,0,deg);
          if(p.z>=0) {
            if(!inSeg) {
              ctx.moveTo(p.x,p.y);
              inSeg=true;

            }
            else ctx.lineTo(p.x,p.y);

          }
          else {
            inSeg=false;

          }

        }

      }
      ctx.stroke();
      ctx.strokeStyle='rgba(200,130,255,0.4)';
      ctx.lineWidth=0.8;
      ctx.beginPath();
      for(const lon of longitudes) {
        let inSeg=false;
        for(let lat=-88;lat<=88;lat+=3) {
          const p=project(lon,lat,deg);
          if(p.z>=0) {
            if(!inSeg) {
              ctx.moveTo(p.x,p.y);
              inSeg=true;

            }
            else ctx.lineTo(p.x,p.y);

          }
          else {
            inSeg=false;

          }

        }

      }
      ctx.stroke();
      ctx.restore();
      ctx.beginPath();
      ctx.arc(cx,cy,R,0,Math.PI*2);
      ctx.strokeStyle='rgba(200,130,255,0.85)';
      ctx.lineWidth=1.3;
      ctx.stroke();
       {
        const starR=R*0.65;
        const waypoints=[[0,0],[starR*0.7,-starR*0.7],[-starR*0.7,starR*0.7],[0,0],[starR*0.7,starR*0.7],[-starR*0.7,-starR*0.7],[0,0],];
        const stepDuration=1.2;
        const totalDuration=stepDuration*(waypoints.length-1);
        const t=(Date.now()/1000)%totalDuration;
        const segIdx=Math.floor(t/stepDuration);
        const segT=(t-segIdx*stepDuration)/stepDuration;
        const ease=segT<0.5?2*segT*segT:1-Math.pow(-2*segT+2,2)/2;
        const from=waypoints[segIdx];
        const to=waypoints[segIdx+1];
        const dx=cx+from[0]+(to[0]-from[0])*ease;
        const dy=cy+from[1]+(to[1]-from[1])*ease;
        ctx.beginPath();
        ctx.arc(dx,dy,4.5,0,Math.PI*2);
        ctx.fillStyle='rgba(220,160,255,0.18)';
        ctx.fill();
        ctx.beginPath();
        ctx.arc(dx,dy,2.5,0,Math.PI*2);
        ctx.fillStyle='rgba(255,200,255,0.95)';
        ctx.fill();

      }
      angle+=0.004;

    }
    function loop(now) {
      if(!document.getElementById('globeCanvas'))return;
      const _globeOk=state.currentScreen==='game'||!!document.getElementById('modeModal');
      if(document.hidden||!_globeOk) {
        window._animRafs['globe']=requestAnimationFrame(loop);
        return;

      }
      draw(now);
      window._animRafs['globe']=requestAnimationFrame(loop);

    }
    window._animRafs['globe']=requestAnimationFrame(loop);

  }
  function getLoggedInName(fallback) {
    const lp=window._localProfile||(typeof _localProfile!=='undefined'?_localProfile:null);
    const cu=(typeof currentUser!=='undefined')?currentUser:null;
    let saved='';
    try {
      saved=localStorage.getItem('playerName')||'';

    }
    catch(e) {

    }
    // Build priority chain, never expose __pending__
    const candidates=[
      lp?.username,
      cu?.user_metadata?.full_name,
      cu?.user_metadata?.display_name,
      saved,
      (typeof state!=='undefined'&&state?.playerName),
      fallback,
      'Player'
    ];
    const raw=candidates.find(v=>v&&v!=='__pending__')||'Guest';
    return raw;

  }
