    setTimeout(function(){var ov=document.createElement('div');ov.style.cssText='position:fixed;inset:0;z-index:9998;pointer-events:none;background:radial-gradient(circle at 50% 40%, rgb(8,32,14), rgb(2,10,4));opacity:1;transition:none;';document.body.appendChild(ov);if(modal)modal.remove();if(modeSpiralCv){if(modeSpiralCv._stopLoop)modeSpiralCv._stopLoop();modeSpiralCv.remove();}_hideGlobalBack();_t('pickOfflineMode→game');goTo('game');requestAnimationFrame(function(){requestAnimationFrame(function(){ov.style.transition='opacity 0.38s cubic-bezier(0.16,1,0.3,1)';ov.style.opacity='0';});});setTimeout(function(){if(ov.parentNode)ov.parentNode.removeChild(ov);},500);},200);

