    _dbgEvent('match','in queue id:'+row.id,'#00e676');
    const channel=sb.channel('match_queue_'+state.playerId).on('postgres_changes',{event:'*',schema:'public',table:'match_queue'},()=>{if(!state.isWaitingForMatch||state._matchFound)return;if(state._matchPollTimer){clearTimeout(state._matchPollTimer);state._matchPollTimer=null;}_matchLoop();}).subscribe(status=>{_tLog('📡 MATCHMAKING: realtime channel → '+status,status==='SUBSCRIBED'?'#00e676':status==='CLOSED'?'#ff5252':'#ffd580');_dbgEvent('match','channel:'+status,status==='SUBSCRIBED'?'#00e676':'#ffd580');if(status==='SUBSCRIBED')_matchLoop();});
    state._queueChannel=channel;
