      state._currentSeed=data.deckSeed;
      buildShuffledDeck(data.deckSeed);
      state._deckReady=true;
      dbg('DECK built seed:'+data.deckSeed+' len:'+shuffledDeck.length);
      const gameArea=document.getElementById('offlineGameArea');
