  let _swipeAbortCtrl=null;
  function initSwipeGesture() {
    const s=document.getElementById('cardScene');
    if(!s)return;
    if(_swipeAbortCtrl)_swipeAbortCtrl.abort();
    _swipeAbortCtrl=new AbortController();
    const sig= {
      signal:_swipeAbortCtrl.signal,passive:true
    };
    s.addEventListener('touchstart',e=>{if(!state.isOffline)return;_swipeStartX=e.touches[0].clientX;_swipeStartY=e.touches[0].clientY;_swipeLocked=false;_swipeDragging=false;},sig);
    s.addEventListener('touchmove',e=>{if(!state.isOffline||_swipeLocked)return;const dx=e.touches[0].clientX-_swipeStartX;const dy=e.touches[0].clientY-_swipeStartY;if(Math.abs(dy)>Math.abs(dx)){_swipeLocked=true;return;}if(Math.abs(dx)>8){_swipeDragging=true;const c3d=document.getElementById('card3d');if(c3d&&c3d.classList.contains('is-flipped')){c3d.classList.add('dragging');c3d.style.transform=`rotateY(180deg) translateX(${-dx * 0.25}px)`;}}},sig);
    s.addEventListener('touchend',e=>{if(!state.isOffline)return;const dx=e.changedTouches[0].clientX-_swipeStartX;const dy=e.changedTouches[0].clientY-_swipeStartY;const c3d=document.getElementById('card3d');if(c3d){c3d.classList.remove('dragging');c3d.style.transform='';}if(_swipeLocked||!_swipeDragging)return;if(Math.abs(dx)<40)return;if(!(c3d&&c3d.classList.contains('is-flipped')))return;if(dx<0)swipeToCard('next');else swipeToCard('prev');},sig);

  }
  function swipeToCard(direction) {
    const scene=document.getElementById('cardScene');
    if(!scene)return;
    if(direction==='next') {
      if(_historyPos===_cardHistory.length-1||_cardHistory.length===0) {
        _cardHistory.push({questionIndex:state.questionIndex,deckIndex:deckIndex});
        _historyPos=_cardHistory.length-1;

      }
      state.questionIndex++;
      deckIndex++;
      if(deckIndex>=shuffledDeck.length)buildShuffledDeck();
      _cardHistory.push({questionIndex:state.questionIndex,deckIndex:deckIndex});
      _historyPos=_cardHistory.length-1;
      scene.classList.remove('swipe-in-right','swipe-in-left');
      if(scene.getAnimations)scene.getAnimations().forEach(a=>a.cancel());
      scene.classList.add('swipe-in-right');

    }
    else {
      if(_historyPos<=0)return;
      _historyPos--;
      const prev=_cardHistory[_historyPos];
      state.questionIndex=prev.questionIndex;
      deckIndex=prev.deckIndex;
      scene.classList.remove('swipe-in-right','swipe-in-left');
      if(scene.getAnimations)scene.getAnimations().forEach(a=>a.cancel());
      scene.classList.add('swipe-in-left');

    }
    gameStarted=true;
    loadQuestion();
    updateTurnUI();
    setTimeout(()=>{scene.classList.remove('swipe-in-right','swipe-in-left');},400);

  }
  window.swipeToCard=swipeToCard;
  function flipCard() {
    _t('flipCard');
    const c3d=document.getElementById('card3d');
    if(!c3d)return;
    const sqbBtn=document.getElementById('showQuestionBtn');
    if(sqbBtn&&sqbBtn.style.display!=='none'&&typeof _sqbVisible!=='undefined'&&_sqbVisible) {
      toggleShowQuestion();
      return;

    }
    if(c3d.classList.contains('is-flipped')) {
      const btnNext=document.getElementById('btnNextQ');
      if(btnNext&&btnNext.style.display!=='none') {
        nextQuestion();

      }
      return;

    }
    if(window._autoFlipTimer) {
      clearTimeout(window._autoFlipTimer);
      window._autoFlipTimer=null;

    }
    c3d.classList.add('is-flipped');
    gameStarted=true;
    if(!state._bellPlayed) {
      state._bellPlayed=true;
      playBell();

    }
    const hint=document.getElementById('tapHint');
    if(hint) {
      hint.style.display='none';

    }
    if(state.isOffline&&_cardHistory.length===0) {
      _cardHistory.push({questionIndex:state.questionIndex,deckIndex:deckIndex});
      _historyPos=0;

    }
    _t('flipCard');

  }
