  function updateGamePlayersStrip() {
    const strip=document.getElementById('gamePlayersStrip');
    if(!strip)return;
    const actions=document.getElementById('gpsActions');
    if(actions)actions.style.display='none';
    const isOnline=!!(state.matchId);
    const isOffline=!!(state.isOffline);
    const isSolo=!!(state.isSolo);
    if(isSolo||isOffline||(!isOnline&&!isOffline)) {
      strip.style.display='none';
      return;

    }
    if(state.answerSubmitted||state.opponentAnswer||state.currentAnswer) {
      strip.style.display='none';
      return;

    }
    strip.style.display='flex';
    const myName=isOffline?(offlinePlayers[offlineCurrentTurn]?.name||'Player'):(getLoggedInName(state.playerName)||state.players?.[0]||'You');
    const myLetter=myName.charAt(0).toUpperCase();
    const gpsMyName=document.getElementById('gpsMyName');
    const gpsMyLetter=document.getElementById('gpsMyLetter');
    const gpsMyAvatar=document.getElementById('gpsMyAvatar');
    if(gpsMyName)gpsMyName.textContent=myName;
    if(gpsMyLetter)gpsMyLetter.textContent=myLetter;
    const _myLoggedIn=!!((typeof window._getCurrentUser==='function'&&window._getCurrentUser())||(window._localProfile&&window._localProfile.username));
    if(gpsMyAvatar) {
      gpsMyAvatar.classList.remove('is-logged','is-guest');
      gpsMyAvatar.classList.add(_myLoggedIn?'is-logged':'is-guest');
      const oldBadge=gpsMyAvatar.querySelector('.gps-guest-badge');
      if(oldBadge)oldBadge.remove();
      if(!_myLoggedIn) {
        const badge=document.createElement('span');
        badge.className='gps-guest-badge';
        badge.textContent='👤';
        gpsMyAvatar.appendChild(badge);

      }

    }
    const oppName=isOnline?(state.opponentName||'-'):(offlinePlayers.length>1?(offlinePlayers.filter((_,i)=>i!==offlineCurrentTurn).map(p=>p.name).join(', ')||'-'):'-');
    const oppLetter=oppName&&oppName!=='-'?oppName.charAt(0).toUpperCase():'?';
    const gpsOppName=document.getElementById('gpsOppName');
    const gpsOppLetter=document.getElementById('gpsOppLetter');
    const gpsOppAvatar=document.getElementById('gpsOppAvatar');
    if(gpsOppName)gpsOppName.textContent=oppName;
    if(gpsOppLetter)gpsOppLetter.textContent=oppLetter;
    const _oppIsGuest=!!(typeof state!=='undefined'&&state.opponentIsGuest);
    if(gpsOppAvatar) {
      gpsOppAvatar.classList.remove('is-logged','is-guest');
      gpsOppAvatar.classList.add(_oppIsGuest?'is-guest':'is-logged');
      const oldBadge=gpsOppAvatar.querySelector('.gps-guest-badge');
      if(oldBadge)oldBadge.remove();
      if(_oppIsGuest) {
        const badge=document.createElement('span');
        badge.className='gps-guest-badge';
        badge.textContent='👤';
        gpsOppAvatar.appendChild(badge);

      }

    }
    const addBtn=document.getElementById('gpsFriendBtn');
    if(addBtn)addBtn.style.display=isOnline&&oppName!=='-'?'inline-block':'none';

  }
