  let _gpsPopupTarget=null;
  function openPlayerPopup(target) {
    let popup=document.getElementById('gpsPlayerPopup');
    const arrow=document.getElementById('gpsPopupArrow');
    const strip=document.getElementById('gamePlayersStrip');
    if(!popup||!strip)return;
    if(popup.closest('.screen')) {
      document.body.appendChild(popup);

    }
    if(_gpsPopupTarget===target&&popup.style.display!=='none') {
      closePlayerPopup();
      return;

    }
    _gpsPopupTarget=target;
    const isMe=(target==='me');
    const name=isMe?(document.getElementById('gpsMyName')?.textContent||'You'):(document.getElementById('gpsOppName')?.textContent||'-');
    const letter=name.charAt(0).toUpperCase();
    if(!isMe&&(name==='-'||name==='')) {
      closePlayerPopup();
      return;

    }
    const popupAvatar=document.getElementById('gpsPopupAvatar');
    const popupLetter=document.getElementById('gpsPopupLetter');
    const popupName=document.getElementById('gpsPopupName');
    const popupStatus=document.getElementById('gpsPopupStatus');
    const popupBtns=document.getElementById('gpsPopupBtns');
    if(popupAvatar) {
      popupAvatar.className='gps-popup-avatar '+(isMe?'popup-me':'popup-opp');

    }
    if(popupLetter)popupLetter.textContent=letter;
    if(popupName)popupName.textContent=name;
    if(popupStatus)popupStatus.textContent=isMe?'you · online':'opponent · online';
    const _cu=(typeof window._getCurrentUser==='function')?window._getCurrentUser():null;
    const _lp=window._localProfile||null;
    const isLoggedIn=!!(_cu||(_lp&&_lp.username));
    if(popupBtns) {
      if(isMe) {
        if(isLoggedIn) {
          popupBtns.innerHTML=`
            <button class="gps-popup-btn" onclick="closePlayerPopup(); openProfileOverlay('me')">
              <span class="gps-popup-btn-icon">👤</span> View my profile
            </button>
            <button class="gps-popup-btn" id="gps-friends-btn" onclick="closePlayerPopup(); openFriendsOverlay()" style="position:relative;">
              <span class="gps-popup-btn-icon">👥</span> Friends
              <span id="gps-friends-badge" style="display:none;position:absolute;top:7px;right:10px;min-width:18px;height:18px;background:#ef4444;border-radius:99px;font-size:0.62rem;font-weight:700;color:white;align-items:center;justify-content:center;padding:0 4px;font-family:'DM Sans',sans-serif;line-height:1;"></span>
            </button>`;

        }
        else {
          popupBtns.innerHTML=`
            <div class="gps-popup-guest-block">
              <span class="gps-popup-guest-icon">🚫</span>
              <div class="gps-popup-guest-text">Profile not available<br><span>Create an account to access your profile</span></div>
            </div>
            <button class="gps-popup-btn gps-popup-btn-register" onclick="closePlayerPopup(); goTo('auth')">
              <span class="gps-popup-btn-icon">✨</span> Create account
            </button>`;

        }

      }
      else {
        if(isLoggedIn) {
          const oppIsGuest=!!(typeof state!=='undefined'&&state.opponentIsGuest);
          if(oppIsGuest) {
            popupBtns.innerHTML=`
              <div class="gps-popup-guest-block">
                <span class="gps-popup-guest-icon">🚫</span>
                <div class="gps-popup-guest-text">Guest player<br><span>This player has no account — profile and friend request unavailable</span></div>
              </div>`;

          }
          else {
            popupBtns.innerHTML=`
              <button class="gps-popup-btn" onclick="closePlayerPopup(); openProfileOverlay('opp')">
                <span class="gps-popup-btn-icon">👤</span> View profile
              </button>
              <button class="gps-popup-btn btn-add" id="gpsPopupAddBtn" onclick="sendGpsFriendRequest(this)" ${state._friendRequestSent ? 'disabled style="opacity:0.45"' : ''}>
                <span class="gps-popup-btn-icon">${state._friendRequestSent ? '✓' : '＋'}</span> ${state._friendRequestSent ? 'Request sent' : 'Add friend'}
              </button>`;

          }

        }
        else {
          popupBtns.innerHTML=`
            <div class="gps-popup-guest-block">
              <span class="gps-popup-guest-icon">🚫</span>
              <div class="gps-popup-guest-text">Not available as guest<br><span>Sign up to add friends &amp; view profiles</span></div>
            </div>
            <button class="gps-popup-btn gps-popup-btn-register" onclick="closePlayerPopup(); goTo('auth')">
              <span class="gps-popup-btn-icon">✨</span> Create account
            </button>`;

        }

      }

    }
    const anchor=document.getElementById(isMe?'gpsMyPlayer':'gpsOppPlayer');
    const stripRect=strip.getBoundingClientRect();
    const anchorRect=anchor?anchor.getBoundingClientRect():stripRect;
    const anchorCenterX=anchorRect.left+anchorRect.width/2;
    const popupWidth=220;
    const minLeft=stripRect.left;
    const maxRight=stripRect.right;
    let popupLeft=anchorCenterX-popupWidth/2;
    if(popupLeft<minLeft+4)popupLeft=minLeft+4;
    if(popupLeft+popupWidth>maxRight-4)popupLeft=maxRight-popupWidth-4;
    const popupTop=stripRect.bottom+8;
    let arrowClass='';
    if(anchorCenterX<popupLeft+40)arrowClass='popup-left';
    else if(anchorCenterX>popupLeft+popupWidth-40)arrowClass='popup-right';
    popup.className='gps-popup '+arrowClass;
    popup.style.left=popupLeft+'px';
    popup.style.top=popupTop+'px';
    popup.style.right='auto';
    popup.style.transform='none';
    const arrowX=anchorCenterX-popupLeft-7;
    if(arrow)arrow.style.left=Math.max(14,Math.min(arrowX,popupWidth-28))+'px';
    popup.style.display='block';
    setTimeout(()=>{function onOutside(e){const p=document.getElementById('gpsPlayerPopup');if(!p||p.style.display==='none'){document.removeEventListener('click',onOutside);return;}if(!p.contains(e.target)&&!document.getElementById('gpsMyPlayer')?.contains(e.target)&&!document.getElementById('gpsOppPlayer')?.contains(e.target)){closePlayerPopup();document.removeEventListener('click',onOutside);}}document.addEventListener('click',onOutside);},80);

  }
