  async function sendGpsFriendRequest(btnEl) {
    const oppName=document.getElementById('gpsOppName')?.textContent||'-';
    if(!oppName||oppName==='-')return;
    const sb=_sbClient();
    const cu=(typeof window._getCurrentUser==='function')?window._getCurrentUser():currentUser;
    const btn=btnEl||document.getElementById('gpsPopupAddBtn')||document.getElementById('gpsFriendBtn');
    if(btn) {
      btn.disabled=true;
      btn.style.opacity='0.45';
      btn.innerHTML='<span class="gps-popup-btn-icon">⏳</span> Sending…';

    }
    if(!sb||!cu) {
      state._friendRequestSent=true;
      if(btn)btn.innerHTML='<span class="gps-popup-btn-icon">✓</span> Request sent';
      showToast('Friend request sent to '+oppName+' ✓','toast-info',2500);
      return;

    }
    const oppId=state.opponentId||null;
    if(!oppId) {
      showToast('Cannot find opponent profile','toast-error',2500);
      if(btn) {
        btn.disabled=false;
        btn.style.opacity='1';
        btn.innerHTML='<span class="gps-popup-btn-icon">＋</span> Add friend';

      }
      return;

    }
    const {
      data:existing
    }
    =await sb.from('friend_requests').select('id, status').eq('from_user_id',cu.id).eq('to_user_id',oppId).maybeSingle();
    if(existing) {
      state._friendRequestSent=true;
      if(btn)btn.innerHTML='<span class="gps-popup-btn-icon">✓</span> '+(existing.status==='accepted'?'Already friends':'Request sent');
      showToast('Request already sent to '+oppName,'toast-info',2500);
      return;

    }
    const myUsername=(typeof _localProfile!=='undefined'&&_localProfile?.username)||cu.email||cu.id;
    const {
      error
    }
    =await sb.from('friend_requests').insert({from_user_id:cu.id,to_user_id:oppId,from_username:myUsername,to_username:oppName,status:'pending'});
    if(error) {
      _ce('Friend request error:',error);
      showToast('Error sending request. Try again.','toast-error',2500);
      if(btn) {
        btn.disabled=false;
        btn.style.opacity='1';
        btn.innerHTML='<span class="gps-popup-btn-icon">＋</span> Add friend';

      }
      return;

    }
    state._friendRequestSent=true;
    if(btn)btn.innerHTML='<span class="gps-popup-btn-icon">✓</span> Request sent';
    showToast('Friend request sent to '+oppName+' ✓','toast-info',2500);

  }
  window.sendGpsFriendRequest=sendGpsFriendRequest;
